DROP TABLE IF EXISTS `lab_achievement`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_achievement` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `title` varchar(500) NOT NULL COMMENT '成果标题',
  `title_en` varchar(500) DEFAULT NULL COMMENT '英文标题',
  `description` text COMMENT '摘要/描述',
  `keywords` varchar(1000) DEFAULT NULL COMMENT '关键词',
  `type` tinyint NOT NULL COMMENT '成果类型：1=论文,2=项目',
  `paper_type` tinyint DEFAULT NULL COMMENT '论文类型：1-7（仅当type=1时有效）',
  `project_type` tinyint DEFAULT NULL COMMENT '项目类型：1-8（仅当type=2时有效）',
  `category_id` bigint DEFAULT NULL COMMENT '成果类型ID（新类型系统）',
  `venue` varchar(300) DEFAULT NULL COMMENT '期刊/会议/发布渠道',
  `publish_date` date DEFAULT NULL COMMENT '发表/公开日期（论文用）',
  `project_start_date` date DEFAULT NULL COMMENT '项目开始日期（项目用）',
  `project_end_date` date DEFAULT NULL COMMENT '项目结束日期（项目用，可空=进行中）',
  `reference` text COMMENT '参考文献/引用信息',
  `link_url` varchar(500) DEFAULT NULL COMMENT '外部链接URL',
  `git_url` varchar(500) DEFAULT NULL COMMENT 'Git 仓库地址',
  `homepage_url` varchar(500) DEFAULT NULL COMMENT '主页/展示页地址',
  `pdf_url` varchar(500) DEFAULT NULL COMMENT 'PDF 下载地址',
  `doi` varchar(128) DEFAULT NULL COMMENT '论文 DOI',
  `funding_amount` decimal(12,2) DEFAULT NULL COMMENT '项目经费（万元）',
  `owner_user_id` bigint NOT NULL COMMENT '成果所有者（创建者）',
  `published` tinyint(1) DEFAULT '0' COMMENT '是否对外发布',
  `is_verified` tinyint(1) DEFAULT '0' COMMENT '是否已审核',
  `extra` json DEFAULT NULL COMMENT '扩展信息（保留字段）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` tinyint(1) DEFAULT '0',
  `creator_id` bigint DEFAULT NULL COMMENT '创建者ID',
  `updater_id` bigint DEFAULT NULL COMMENT '更新者ID',
  PRIMARY KEY (`id`),
  KEY `idx_type_publish_date` (`type`,`publish_date`),
  KEY `idx_type_project_dates` (`type`,`project_start_date`,`project_end_date`),
  KEY `idx_published_publish_date` (`published`,`publish_date`),
  KEY `idx_owner_user_id` (`owner_user_id`),
  KEY `idx_doi` (`doi`),
  KEY `idx_deleted` (`deleted`),
  KEY `idx_category_id` (`category_id`),
  CONSTRAINT `fk_ach_owner_user` FOREIGN KEY (`owner_user_id`) REFERENCES `lab_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=317 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='实验室成果表';
/*!40101 SET character_set_client = @saved_cs_client */;

