--
-- Table structure for table `lab_achievement_author`
--

DROP TABLE IF EXISTS `lab_achievement_author`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_achievement_author` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `achievement_id` bigint NOT NULL COMMENT '成果ID',
  `user_id` bigint DEFAULT NULL COMMENT '内部作者user_id；NULL为外部作者',
  `name` varchar(100) NOT NULL COMMENT '作者姓名（内部作者可冗余）',
  `name_en` varchar(100) DEFAULT NULL,
  `affiliation` varchar(300) DEFAULT NULL,
  `author_order` int NOT NULL COMMENT '作者顺序（>0）',
  `is_corresponding` tinyint(1) DEFAULT '0' COMMENT '是否通讯作者',
  `role` varchar(100) DEFAULT NULL COMMENT '作者角色/贡献',
  `visible` tinyint(1) DEFAULT '1' COMMENT '仅对内部作者生效：是否在该用户个人页可见',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除 0=存在 1=删除',
  `creator_id` bigint DEFAULT NULL COMMENT '创建者ID',
  `updater_id` bigint DEFAULT NULL COMMENT '更新者ID',
  `email` varchar(100) DEFAULT NULL COMMENT '邮箱',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_achievement_author_order` (`achievement_id`,`author_order`,`deleted`),
  UNIQUE KEY `uniq_achievement_user` (`achievement_id`,`user_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_achievement_id` (`achievement_id`),
  KEY `idx_user_visible_order` (`user_id`,`visible`,`author_order`),
  KEY `idx_lab_ach_author_ach_deleted` (`achievement_id`,`deleted`),
  CONSTRAINT `fk_author_achievement` FOREIGN KEY (`achievement_id`) REFERENCES `lab_achievement` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_author_user` FOREIGN KEY (`user_id`) REFERENCES `lab_user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1186 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='成果作者表（内外部作者统一)';
/*!40101 SET character_set_client = @saved_cs_client */;

