--
-- Table structure for table `lab_achievement_category`
--

DROP TABLE IF EXISTS `lab_achievement_category`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_achievement_category` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '类型ID',
  `parent_id` bigint DEFAULT NULL COMMENT '父类型ID，NULL表示一级类型',
  `category_code` varchar(50) NOT NULL COMMENT '类型编码（用于兼容现有逻辑）',
  `category_name` varchar(100) NOT NULL COMMENT '类型名称',
  `category_name_en` varchar(100) DEFAULT NULL COMMENT '英文名称',
  `description` text COMMENT '类型描述',
  `sort_order` int DEFAULT '0' COMMENT '排序顺序',
  `is_system` tinyint(1) DEFAULT '0' COMMENT '是否系统内置类型（不可删除）',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `icon` varchar(100) DEFAULT NULL COMMENT '图标',
  `color` varchar(20) DEFAULT NULL COMMENT '颜色标识',
  `creator_id` bigint DEFAULT NULL COMMENT '创建者ID',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater_id` bigint DEFAULT NULL COMMENT '更新者ID',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '逻辑删除标记',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_code_deleted` (`category_code`,`deleted`),
  UNIQUE KEY `uk_parent_name_deleted` (`parent_id`,`category_name`,`deleted`),
  KEY `idx_parent_id` (`parent_id`),
  KEY `idx_category_code` (`category_code`),
  KEY `idx_sort_order` (`sort_order`),
  KEY `idx_is_active` (`is_active`),
  KEY `idx_deleted` (`deleted`),
  CONSTRAINT `fk_category_parent` FOREIGN KEY (`parent_id`) REFERENCES `lab_achievement_category` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='成果类型表';
/*!40101 SET character_set_client = @saved_cs_client */;

