DROP TABLE IF EXISTS `lab_user_relationship`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_user_relationship` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '关系ID',
  `teacher_id` bigint NOT NULL COMMENT '导师ID',
  `student_id` bigint NOT NULL COMMENT '学生ID',
  `relationship_type` tinyint DEFAULT '1' COMMENT '关系类型：1=导师关系',
  `start_date` date DEFAULT NULL COMMENT '关系开始时间',
  `end_date` date DEFAULT NULL COMMENT '关系结束时间（毕业等）',
  `status` tinyint DEFAULT '1' COMMENT '状态：1=活跃,2=已结束',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `creator_id` bigint DEFAULT NULL COMMENT '创建者ID',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater_id` bigint DEFAULT NULL COMMENT '更新者ID',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_teacher_student` (`teacher_id`,`student_id`),
  KEY `idx_teacher` (`teacher_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_status` (`status`),
  KEY `idx_create_time` (`create_time`),
  KEY `idx_teacher_status` (`teacher_id`,`status`),
  KEY `idx_student_status` (`student_id`,`status`),
  KEY `idx_active_relationships` (`status`,`teacher_id`,`student_id`),
  CONSTRAINT `fk_relationship_student` FOREIGN KEY (`student_id`) REFERENCES `lab_user` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_relationship_teacher` FOREIGN KEY (`teacher_id`) REFERENCES `lab_user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='实验室师生关系表';
